import { useEffect, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Users,
  UsersRound,
  ClipboardCheck,
  AlertTriangle,
  CheckCircle,
  XCircle,
} from "lucide-react";

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [pending, setPending] = useState({
    users: [],
    students: [],
    payments: [],
    results: [],
    announcements: [],
    total: 0,
  });

  const [loading, setLoading] = useState(true);

  const user = authService.getUser();
  const isAdmin =
    user?.role === "school_admin" || user?.role === "admin";

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const statsRes = await apiClient.get("/dashboard/stats");
      setStats(statsRes.data);

      if (isAdmin) {
        const pendingRes = await apiClient.get("/admin/pending");
        setPending(pendingRes.data);
      }
    } catch (err) {
      console.error(err);
      toast.error("Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    {
      title: "Students",
      value: stats?.total_students || 0,
      icon: Users,
    },
    {
      title: "Staff",
      value: stats?.total_staff || 0,
      icon: UsersRound,
    },
    {
      title: "Pending Approvals",
      value: pending?.total || 0,
      icon: ClipboardCheck,
    },
  ];

  if (loading) {
    return <div className="text-slate-400">Loading dashboard...</div>;
  }

  return (
    <div className="space-y-6">

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {statCards.map((s, i) => {
          const Icon = s.icon;
          return (
            <Card key={i} className="bg-[#1A2332] border-[#2A3B4F]">
              <CardContent className="p-4 flex justify-between items-center">
                <div>
                  <p className="text-slate-400 text-sm">{s.title}</p>
                  <p className="text-white text-2xl font-bold">{s.value}</p>
                </div>
                <Icon className="text-emerald-400" />
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* APPROVALS */}
      {isAdmin && (
        <div className="bg-[#1A2332] p-4 rounded-xl border border-[#2A3B4F]">
          <div className="flex items-center gap-2 mb-4">
            <AlertTriangle className="text-amber-400" />
            <h2 className="text-white font-semibold">
              Pending Approvals ({pending.total})
            </h2>
          </div>

          <Tabs defaultValue="users">

            <TabsList className="bg-[#0F1A2A]">
              <TabsTrigger value="users">Users</TabsTrigger>
              <TabsTrigger value="students">Students</TabsTrigger>
              <TabsTrigger value="payments">Payments</TabsTrigger>
              <TabsTrigger value="results">Results</TabsTrigger>
              <TabsTrigger value="announcements">Announcements</TabsTrigger>
            </TabsList>

            {/* USERS */}
            <TabsContent value="users">
              {pending.users.map((u) => (
                <Card key={u.id} className="mt-2">
                  <CardContent className="flex justify-between p-3">
                    <p className="text-white">{u.full_name}</p>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>

            {/* STUDENTS */}
            <TabsContent value="students">
              {pending.students.map((s) => (
                <Card key={s.id} className="mt-2">
                  <CardContent className="flex justify-between p-3">
                    <p className="text-white">{s.full_name}</p>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>

            {/* PAYMENTS */}
            <TabsContent value="payments">
              {pending.payments.map((p) => (
                <Card key={p.id} className="mt-2">
                  <CardContent className="flex justify-between p-3">
                    <p className="text-white">KES {p.amount}</p>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>

            {/* RESULTS */}
            <TabsContent value="results">
              {pending.results.map((r) => (
                <Card key={r.id} className="mt-2">
                  <CardContent className="flex justify-between p-3">
                    <p className="text-white">{r.subject}</p>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>

            {/* ANNOUNCEMENTS */}
            <TabsContent value="announcements">
              {pending.announcements.map((a) => (
                <Card key={a.id} className="mt-2">
                  <CardContent className="flex justify-between p-3">
                    <p className="text-white">{a.title}</p>
                  </CardContent>
                </Card>
              ))}
            </TabsContent>

          </Tabs>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
